from openai import OpenAI
import json

client = OpenAI()

# Schema must use additionalProperties: false on all objects in strict mode
schema = {
    "type": "object",
    "properties": {
        "action": {
            "type": "string",
            "enum": ["search", "read_file", "write_file", "terminate"]
        },
        "arguments": {
            "type": "object",
            "properties": {
                "query":   {"type": "string"},
                "path":    {"type": "string"},
                "content": {"type": "string"}
            },
            "additionalProperties": False
        },
        "reasoning": {
            "type": "string",
            "description": "Brief justification for choosing this action"
        },
        "confidence": {
            "type": "number",
            "minimum": 0,
            "maximum": 1,
            "description": "Confidence score between 0.0 and 1.0"
        }
    },
    "required": ["action", "arguments", "reasoning", "confidence"],
    "additionalProperties": False
}

response = client.chat.completions.create(
    model="gpt-4o-2024-08-06",
    messages=[
        {"role": "system", "content": "You are an agent planner. Choose the best next action."},
        {"role": "user",   "content": "Find all Python files in /src that import pandas."}
    ],
    response_format={
        "type": "json_schema",
        "json_schema": {
            "name": "agent_action",
            "strict": True,       # <-- enforces at decode time
            "schema": schema
        }
    }
)

# Check for refusal before parsing
choice = response.choices[0]
if choice.finish_reason != "stop":
    raise RuntimeError(f"Model refused: {choice.finish_reason}")

# Always valid — no try/except needed for structural errors
action = json.loads(choice.message.content)
print(action["action"])      # guaranteed to be one of the enum values
print(action["confidence"])  # guaranteed to be a number between 0 and 1

from pydantic import BaseModel, Field
from openai import OpenAI

client = OpenAI()

class AgentAction(BaseModel):
    action: str = Field(description="One of: search, read_file, write_file, terminate")
    path: str | None = Field(default=None, description="File path for read/write actions")
    query: str | None = Field(default=None, description="Search query")
    reasoning: str = Field(description="Why this action was chosen")
    confidence: float = Field(ge=0.0, le=1.0)

def add_no_additional_props(schema: dict) -> dict:
    if schema.get("type") == "object":
        schema.setdefault("additionalProperties", False)
        for prop in schema.get("properties", {}).values():
            add_no_additional_props(prop)
    if "items" in schema:
        add_no_additional_props(schema["items"])
    for sub in schema.get("$defs", {}).values():
        add_no_additional_props(sub)
    return schema

schema = add_no_additional_props(AgentAction.model_json_schema())

response = client.chat.completions.create(
    model="gpt-4o-2024-08-06",
    messages=[{"role": "user", "content": "Search for pandas imports in /src/analysis/"}],
    response_format={
        "type": "json_schema",
        "json_schema": {"name": "agent_action", "strict": True, "schema": schema}
    }
)

choice = response.choices[0]
if choice.finish_reason != "stop":
    raise RuntimeError(f"Unexpected finish_reason: {choice.finish_reason}")

action = AgentAction.model_validate_json(choice.message.content)
print(action.action)       # str, guaranteed to be one of the enum values
print(action.confidence)   # float, guaranteed in [0, 1]

import google.generativeai as genai
from google.generativeai.types import GenerationConfig
import json

genai.configure(api_key="YOUR_GEMINI_API_KEY")

schema = {
    "type": "object",
    "properties": {
        "label": {
            "type": "string",
            "enum": ["positive", "negative", "neutral"],
            "description": "Sentiment classification"
        },
        "score": {
            "type": "number",
            "description": "Confidence score between 0.0 and 1.0"
        },
        "key_phrases": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Phrases that most influenced the classification"
        },
        "explanation": {
            "type": "string",
            "description": "One-sentence justification"
        }
    },
    "required": ["label", "score", "key_phrases", "explanation"]
}

model = genai.GenerativeModel("gemini-1.5-pro-latest")

response = model.generate_content(
    "Classify: 'The new structured output API eliminated our entire retry infrastructure.'",
    generation_config=GenerationConfig(
        response_mime_type="application/json",
        response_schema=schema
    )
)

result = json.loads(response.text)
print(result["label"])        # always one of: positive, negative, neutral
print(result["score"])        # always a number
print(result["key_phrases"])  # always a list of strings
print(result["explanation"])  # always a string

import anthropic

client = anthropic.Anthropic()

extract_tool = {
    "name": "extract_invoice",
    "description": "Extract structured invoice data from unstructured text.",
    "input_schema": {
        "type": "object",
        "properties": {
            "invoice_number": {"type": "string"},
            "vendor_name":    {"type": "string"},
            "total_amount":   {"type": "number"},
            "currency":       {"type": "string", "enum": ["USD", "EUR", "GBP", "JPY"]},
            "line_items": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "description": {"type": "string"},
                        "quantity":    {"type": "integer"},
                        "unit_price":  {"type": "number"}
                    },
                    "required": ["description", "quantity", "unit_price"]
                }
            }
        },
        "required": ["invoice_number", "vendor_name", "total_amount", "currency", "line_items"]
    }
}

message = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=1024,
    tools=[extract_tool],
    tool_choice={"type": "tool", "name": "extract_invoice"},  # force this tool
    messages=[{"role": "user", "content": "Invoice #INV-2024-0042, Acme Corp, $1600 USD, 2 line items: hosting $1200, support $400"}]
)

tool_use = next(b for b in message.content if b.type == "tool_use")
invoice = tool_use.input   # always conforms to input_schema

print(invoice["invoice_number"])   # "INV-2024-0042"
print(invoice["total_amount"])     # 1600.0  — a number, never a string
print(len(invoice["line_items"])) # 2

from openai import OpenAI
from pydantic import BaseModel, Field
import boto3, psycopg2, os

client = OpenAI()

class LineItem(BaseModel):
    description: str
    quantity: int
    unit_price: float = Field(ge=0)

class Invoice(BaseModel):
    invoice_number: str
    vendor_name: str
    invoice_date: str
    due_date: str | None = None
    currency: str = Field(pattern="^[A-Z]{3}$")
    total: float = Field(ge=0)
    line_items: list[LineItem]

def _no_additional(s: dict) -> None:
    if s.get("type") == "object":
        s["additionalProperties"] = False
        for v in s.get("properties", {}).values():
            _no_additional(v)
    if "items" in s:
        _no_additional(s["items"])

_SCHEMA = Invoice.model_json_schema()
_no_additional(_SCHEMA)

def extract_invoice(raw_text: str) -> Invoice:
    resp = client.chat.completions.create(
        model="gpt-4o-2024-08-06",
        messages=[
            {"role": "system", "content": "Extract invoice data. Use null for absent fields. Amounts are float."},
            {"role": "user", "content": raw_text}
        ],
        response_format={
            "type": "json_schema",
            "json_schema": {"name": "invoice_v2", "strict": True, "schema": _SCHEMA}
        }
    )
    choice = resp.choices[0]
    if choice.finish_reason != "stop":
        raise ValueError(f"Unexpected finish: {choice.finish_reason}")
    return Invoice.model_validate_json(choice.message.content)

def handler(event, context):
    rec = event["Records"][0]["s3"]
    raw = boto3.client("s3").get_object(
        Bucket=rec["bucket"]["name"], Key=rec["object"]["key"]
    )["Body"].read().decode()

    invoice = extract_invoice(raw)   # no retry, no try/except for parse errors

    conn = psycopg2.connect(os.environ["DB_URL"])
    with conn.cursor() as cur:
        cur.execute(
            "INSERT INTO invoices (number, vendor, total, currency) VALUES (%s,%s,%s,%s)"
            " ON CONFLICT (number) DO UPDATE SET total = EXCLUDED.total",
            (invoice.invoice_number, invoice.vendor_name, invoice.total, invoice.currency)
        )
    conn.commit(); conn.close()
    return {"statusCode": 200, "invoice": invoice.invoice_number}

